import json

D = lambda i,t,s,e,n,c,nx: {"id":i,"text":t,"speaker":"我","avatar":"厂","score":s,"triggeredEvent":e,"historicalNote":n,"consequence":c,"nextActId":nx}
A = lambda i,t,k,tm,s,n,dls: {"id":i,"title":t,"isKeyAct":k,"timeMarker":tm,"sceneDescription":s,"npcDialogues":n,"dialogues":dls}
N = lambda sp,tx,av: {"speaker":sp,"text":tx,"avatar":av}

acts = []

# 4c
acts.append(A("act-4c","管理创新",False,"1788年",
"工厂规模扩大后，管理成了大问题。几百个工人，几十台机器，如何高效地组织生产，让你绞尽脑汁。传统的手工业管理方式已经完全不适用了，你必须探索新的管理方法。",
[N("工头罗伯特","老板，现在人太多了，我管不过来啊。迟到早退的，偷懒磨洋工的，根本管不过来。","罗"),N("会计托马斯","账目也越来越复杂，原料、成品、工资、成本，我每天算到头昏眼花，还经常出错。","托")],
[D("d1","我要建立部门制，分车间、分工段，层层负责。",90,"你建立了分级管理制度，将工厂分成几个车间，每个车间设主任，下面分段设工长。层层负责，管理效率大大提高了。","工厂制度的重要特征就是分级管理和专业化分工。阿克莱特最早建立了比较完善的工厂管理制度，被称为\"工厂制度之父\"。","分级管理，效率提升","act-5"),
D("d2","我要搞计件工资，干得多拿得多，不用人监督。",88,"你推行计件工资制，工人的收入直接和产量挂钩。不用监督，工人们自己就会努力干活。管理简单了，产量也上去了。","计件工资是资本主义工资的一种基本形式。它表面上多劳多得，实际上可以更巧妙地提高剥削程度，因为它迫使工人为了多挣工资而自动提高劳动强度。","计件工资，自动驱动","act-5"),
D("d3","建立标准化的操作流程，让每个人都按规范来。",85,"你制定了标准化的操作流程和质量标准，每个工人都必须按规范操作。产品质量稳定了，管理也简单了很多。","标准化生产是现代工业的重要特征。泰勒制就是将标准化推向极致的科学管理方法，极大地提高了生产效率。","标准化生产，质量稳定","act-5"),
D("d4","我要用皮鞭和罚款来管理，看谁敢偷懒。",62,"你采用了严苛的管理方式，迟到罚款，偷懒挨打。工人们在高压下战战兢兢，但人人心中都有怨气，随时可能爆发。","工业革命初期，很多工厂主采用高压手段管理工人。监工带着皮鞭巡厂，是当时常见的景象。这种残酷的管理方式激起了工人的强烈反抗。","高压管理，怨声载道","act-5"),
D("d5","引进复式记账法，把账目搞清楚，成本算明白。",82,"你聘请了专业的会计师，引入复式记账法，建立了完善的成本核算体系。每一笔支出、每一分利润都清清楚楚，管理起来心中有数。","复式记账法是现代会计的基础。工业革命时期，随着企业规模扩大，对会计和财务管理的要求越来越高，推动了会计学的发展。","成本核算，心中有数","act-5"),
D("d6","我要选几个能干的工头，让他们帮我管。",75,"你提拔了几个能干的老工人当工头，让他们负责日常管理。工人们都是老相识，管理起来比较顺畅。但也容易形成小圈子，产生裙带关系。","工头制度是工厂管理的早期形式。工头通常从熟练工人中提拔，他们既懂技术又有威信，是连接资本家和普通工人的中间阶层。","工头管理，顺畅有效","act-5"),
D("d7","建立上下班打卡制度，严格考勤。",78,"你安装了打卡机，实行严格的考勤制度。迟到早退都要扣工资。工人的时间观念加强了，工厂的秩序也好了很多。","考勤制度是工厂纪律的重要组成部分。工业革命把人们变成了\"时间的奴隶\"，准时上班、按钟点劳动，成为产业工人的基本生活方式。","严格考勤，秩序井然","act-5"),
D("d8","我要搞全面质量管理，不让一件次品出厂。",86,"你建立了严格的质量检验制度，每道工序都要检查，不合格的产品绝不出厂。虽然增加了成本，但你的产品赢得了质量好的声誉。","质量管理是企业管理的重要内容。在工业革命时期，随着大规模生产的发展，质量控制变得越来越重要。","质量至上，赢得声誉","act-5"),
D("d9","我要去参观阿克莱特的工厂，学习他的管理经验。",84,"你专程去克罗姆福德参观阿克莱特的工厂，学习他的管理方法。这次取经让你大开眼界，回来后对工厂进行了全面的管理改革。","阿克莱特不仅是技术发明家，更是管理创新者。他建立的工厂管理制度成为后来工厂的样板，影响深远。","参观学习，取到真经","act-5")]))

# 5c
acts.append(A("act-5c","女工童工",False,"1795年",
"工厂里的女工和童工越来越多了。她们工资低，干活仔细，很受工厂主欢迎。但是，她们的处境也最悲惨——长时间劳动，微薄的工资，恶劣的工作条件。你心里清楚这样不对，但又舍不得廉价的劳动力。",
[N("女工伊丽莎白","老板，我们每天干12个小时，拿的工资还不到男工的一半。这也太不公平了吧？","伊"),N("童工小汤姆","叔叔，我好累啊，我的手都被机器扎破了，能不能让我歇一会儿？","汤")],
[D("d1","必须改变！提高女工童工工资，缩短她们的工作时间。",90,"你下定决心，大幅提高女工和童工的工资，缩短她们的工作时间，还改善了劳动条件。虽然成本增加了，但工人的积极性大大提高了。","工业革命时期，女工和童工的处境最为悲惨。她们的工资通常只有男工的三分之一到一半，劳动时间却一样长。她们是最底层的劳动者。","提高待遇，改善处境","act-6"),
D("d2","能多赚一分是一分，反正她们也干不了重活。",60,"你觉得女工童工工价低，正好可以降低成本，多赚利润。你继续大量雇佣女工童工，尽量压低她们的工资。","对女工和童工的剥削是资本原始积累的重要方式。资本家利用她们的弱势地位，榨取更多的剩余价值。这是资本主义发展史中不光彩的一页。","压低工资，榨取利润","act-6"),
D("d3","女工归女工，我把她们安排到适合的岗位上。",82,"你根据女工的特点，把她们安排到纺织、包装等适合的岗位上。她们干得又快又好，效率不比男工差。","纺织业是女工最集中的行业。因为女工手指灵巧，适合从事精细的纺织工作。到19世纪中期，纺织厂中女工的数量已经超过了男工。","因材施用，各尽所能","act-6"),
D("d4","我要办个夜校，让童工们晚上能学点儿文化。",88,"你在工厂办了夜校，让童工们每天干完活后能学两个小时的文化知识。虽然孩子们还是很累，但至少有了改变命运的机会。","工业革命时期，工人教育逐渐兴起。一些有远见的工厂主、慈善家和宗教人士创办了各种工人学校，推动了工人阶级文化水平的提高。","开办夜校，点亮希望","act-6"),
D("d5","女工干活还行，童工就算了，太残忍了。",78,"你决定不再雇佣童工，但继续雇佣女工。你觉得妇女出来工作赚钱，也算是自食其力，比童工好得多。","工业革命时期，大量妇女走出家庭，进入工厂工作。这一方面是剥削，另一方面也提高了妇女的经济地位，为妇女解放创造了条件。","禁用童工，保留女工","act-6"),
D("d6","我要设立女工保护规定，孕期可以休工。",85,"你制定了女工保护规定，怀孕期间可以休工，哺乳期可以减少工时。你的做法在当时是非常开明的，赢得了女工们的感激。","女工劳动保护是社会进步的标志。工业革命时期，首先是一些有良知的企业家自发采取保护措施，后来才逐渐上升为国家法律。","女工保护，人文关怀","act-6"),
D("d7","男女同工同酬，干一样的活拿一样的钱。",92,"你做出了一个惊世骇俗的决定——男女同工同酬！消息传开，所有人都震惊了。女工们更是喜极而泣，干活倍加努力。","男女同工同酬是妇女解放的重要目标。但在整个19世纪，这都只是一个美好的愿望。直到20世纪，同工同酬才逐渐成为法律规定。","同工同酬，石破天惊","act-6"),
D("d8","童工太小了容易出事，我只收十二岁以上的。",72,"你规定只招收十二岁以上的童工，太小的不收。虽然这仍然是使用童工，但至少比那些五六岁就进厂的强多了。","在工业革命早期，童工的年龄非常小，有的甚至只有五六岁。后来随着社会进步和工厂立法，童工的年龄线才逐步提高。","提高年龄，稍有改善","act-6"),
D("d9","我要为女工建宿舍，保护她们的安全。",80,"你为女工修建了单独的宿舍，聘请了女管理员，保障她们的安全和生活。女工们有了安身之所，工作也更安心了。","早期工厂中，女工的安全和尊严经常得不到保障。一些有良心的工厂主会为女工提供住宿和保护，这在当时是非常难得的。","女工宿舍，保障安全","act-6")]))

# 6c
acts.append(A("act-6c","事故频发",False,"1792年",
"工厂里的机器越来越多，工伤事故也越来越频繁。断手断脚是家常便饭，甚至还有人命关天的大事。工人们人心惶惶，你也焦头烂额。怎么办？",
[N("受伤工人的妻子","老爷啊，我丈夫的手被机器轧断了，以后可怎么活啊！您可怜可怜我们孤儿寡母吧！","妻"),N("工头罗伯特","老板，这已经是这个月第三起事故了。再这样下去，没人敢来咱们厂干活了。","罗")],
[D("d1","立刻安装安全防护装置，人命关天！",88,"你痛下决心，拨出专款为所有机器安装安全防护装置，还制定了安全操作规程。事故率大大下降，工人们也安心了。","工业革命时期，工厂安全条件极差，工伤事故频发。经过工人阶级的长期斗争和社会进步人士的呼吁，安全立法才逐步建立起来。","安全第一，防患未然","act-7"),
D("d2","事故在所难免，赔点钱就是了。",62,"你觉得工厂这么大，机器这么多，事故是难免的。死了伤了，赔几个钱了事。在你眼里，工人的命还不如机器值钱。","工业革命初期，工人的生命安全根本没有保障。资本家为了追求利润，完全不顾工人死活。工伤事故频繁发生，工人的权益得不到任何保障。","漠视生命，金钱至上","act-7"),
D("d3","我要设立工伤抚恤金，让受伤的工人有个着落。",85,"你设立了工伤抚恤金制度，因工受伤的工人可以得到治疗和生活补助，因工死亡的家属可以得到抚恤。这在当时是非常难得的。","工伤保险是社会保障的重要组成部分。但在工业革命早期，这根本不存在。工人受伤或死亡，只能自认倒霉，或者靠雇主的施舍。","工伤抚恤，雪中送炭","act-7"),
D("d4","加强安全教育，让工人自己小心点。",75,"你加强了安全教育，要求工人严格按操作规程来，还设立了安全奖。事故有所减少，但根源问题还是没有解决。","安全教育是减少事故的重要手段。但如果缺乏必要的安全防护设施，光靠工人自己小心是远远不够的。","安全教育，提高意识","act-7"),
D("d5","我要请医生驻厂，受伤了能及时救治。",80,"你聘请了一名医生常驻工厂，工人受伤可以第一时间得到救治。虽然不能防止事故，但至少能减少死亡和残疾。","厂医制度是企业福利的雏形。一些大企业开始聘请驻厂医生，为工人提供基本的医疗服务。这在一定程度上改善了工人的医疗条件。","驻厂医生，及时救治","act-7"),
D("d6","出了事故的工人统统开除，省得麻烦。",60,"你规定凡是出了工伤事故的工人，一律开除，工厂概不负责。你的冷酷无情让工人们心寒，也为日后的冲突埋下了种子。","工业革命初期，资本家对待受伤工人的态度极其冷酷。工人一旦失去劳动能力，就会被一脚踢开，任其自生自灭。","冷酷无情，扫地出门","act-7"),
D("d7","我要改进机器设计，从源头减少事故。",86,"你组织工程师对机器进行改进，增加安全防护，优化操作方式。从源头上减少了事故发生的可能性。","技术进步是改善安全生产的根本途径。随着技术的发展和安全意识的提高，机器的安全性能越来越好，事故率也逐步下降。","技术改进，源头治理","act-7"),
D("d8","建立安全巡查制度，每天检查，消除隐患。",82,"你建立了每日安全巡查制度，安排专人检查设备和操作，及时发现和消除隐患。事故率明显下降了。","安全检查制度是安全生产的重要保障。定期排查隐患，可以有效预防事故的发生。","每日巡查，消除隐患","act-7"),
D("d9","我要为工人买保险，出了事由保险公司赔付。",84,"你为所有工人购买了意外伤害保险，出了事故由保险公司赔付。这样既保障了工人的权益，也减轻了你的负担。","意外伤害保险是商业保险的一种。随着保险业的发展，一些企业开始为员工购买保险，这是企业风险管理的一种方式。","保险保障，分散风险","act-7")]))

# 7c
acts.append(A("act-7c","运河时代",False,"1790年",
"工业发展了，运输成了大问题。原料要运进来，产品要运出去，靠马车又慢又贵。运河成了当时的高速公路。你要不要投资运河运输？",
[N("船运老板布朗","老板，运河开通后，运输成本能降一半，速度还快。投资运河绝对赚大钱！","布"),N("马车运输商托马斯","别听他的！运河就是个无底洞，不知道要砸多少钱进去，而且修得成修不成都难说！","托")],
[D("d1","我要投资运河，这是改变时代的大事！",90,"你果断投资了曼彻斯特至利物浦的运河项目。运河开通后，运输成本大幅下降，你的产品更有竞争力了，运河股票也涨了好几倍。","18世纪中后期，英国掀起了运河开凿热潮。运河大大降低了运输成本，推动了工业革命的发展。布里奇沃特公爵运河是其中最著名的一条。","投资运河，收获丰厚","act-8"),
D("d2","先投资一小部分试试水，看看情况再说。",78,"你谨慎地投资了一小笔钱。运河开通后确实赚钱了，但因为投资太少，收益有限。你有些后悔当初不够大胆。","运河投资在当时是一项热门但有风险的事业。有人一夜暴富，也有人血本无归。谨慎投资虽然收益有限，但风险也小。","小额投资，收益有限","act-8"),
D("d3","我要亲自去考察一下，眼见为实。",85,"你亲自乘船沿已有的运河走了一趟，亲眼目睹了运河运输的便利。回来后你大举投资运河，获得了丰厚的回报。","实践出真知。实地考察后再做决策，比道听途说要可靠得多。在工业革命时期，很多企业家都是亲力亲为的实干家。","实地考察，坚定信心","act-8"),
D("d4","运河风险太大，我还是继续用马车吧。",65,"你觉得运河投资太大、风险太高，决定继续使用传统的马车运输。但随着运河的开通，你的运输成本比竞争对手高很多，逐渐失去了价格优势。","在技术变革的时代，保守就意味着落后。拒绝新的运输方式，虽然避免了风险，但也丧失了机遇。","保守观望，逐渐落后","act-8"),
D("d5","我不直接投资运河，我买运河沿岸的地皮。",88,"你没有直接投资运河，而是大量购买运河沿岸的土地。运河开通后，地价飞涨，你靠卖地赚了一大笔，比投资运河本身还赚得多。","交通带动地产升值，这是一条不变的规律。聪明的投资者不直接投资交通，而是投资沿线的土地，往往能获得更高的回报。","投资地产，坐地升值","act-8"),
D("d6","我要组建自己的运输船队，掌控运输环节。",82,"你组建了自己的运河运输船队，掌控了从原料到产品的整个运输链条。不仅降低了成本，还能保证运输的时效性。","垂直一体化是企业发展的重要战略。将运输环节也纳入自己的控制范围，可以大大提高效率，降低成本。","自有船队，掌控全链","act-8"),
D("d7","我要和其他工厂主联合，共同投资运河。",80,"你联合了几家大工厂主，共同出资成立运河公司。大家利益均沾，风险共担。运河修通后，所有人都受益了。","联合投资是应对大型项目的有效方式。通过集合众人的力量，可以办成单个企业力所不及的大事。","联合投资，共担风险","act-8"),
D("d8","运河是未来，但我更看好未来的铁路。",86,"你敏锐地预感到，运河虽然现在红火，但未来属于铁路。你没有在运河上投入太多，而是把资金留着，准备将来投资铁路。","远见卓识是成功企业家的重要品质。在运河时代就预见到铁路的未来，需要超越常人的眼光。后来的历史证明了这种远见的价值。","洞察未来，预留资金","act-8"),
D("d9","我对运输不感兴趣，我还是专注于生产吧。",70,"你觉得自己的本行是生产，运输还是交给专业的人去做吧。你专注于改进生产，产品质量和成本都做到了行业领先。","专业化分工是经济发展的趋势。不是什么都要自己做，把专业的事交给专业的人，往往效率更高。","专注生产，做到极致","act-8")]))

# 9c
acts.append(A("act-9c","欧文实验",False,"1815年",
"你听说了欧文在新拉纳克工厂的实验——他改善工人待遇，缩短工时，创办学校，居然还能赚钱！这对你的观念造成了巨大的冲击。难道善待工人和赚钱，真的可以兼得吗？",
[N("从新拉纳克回来的朋友","你真应该去新拉纳克看看！欧文的工厂里，工人笑容满面，孩子都在上学，产量居然比我们的工厂还高！","朋"),N("保守的工厂主同行","欧文那是异想天开！他那套根本长久不了，等着瞧吧，他迟早要破产！","同")],
[D("d1","我要亲自去新拉纳克看看，欧文是怎么做到的！",90,"你专程前往苏格兰的新拉纳克，实地考察欧文的工厂。这次考察彻底改变了你的观念。回来后你对工厂进行了大刀阔斧的改革。","罗伯特·欧文是19世纪初最伟大的空想社会主义者之一。他在新拉纳克工厂进行了著名的实验，证明了善待工人不仅符合道德，也符合经济利益。","亲赴新拉纳克，观念剧变","act-10"),
D("d2","欧文就是个空想家，他那套行不通的。",65,"你对欧文的实验嗤之以鼻，认为那只是空想家的异想天开，根本不可能长久。你继续用老办法管理工厂。","欧文的实验在当时确实惊世骇俗，很多人不理解，也不相信。但历史证明，欧文的很多设想后来都变成了现实。","嗤之以鼻，不为所动","act-10"),
D("d3","我可以试试他的一些做法，但不能全学。",78,"你决定借鉴欧文的一些做法，比如缩短一点工时，改善一下伙食，但不敢走得太远。改善之后，工人的积极性确实有所提高。","从善如流但循序渐进，是很多务实的企业家的选择。他们会吸收新思想的合理部分，但不会贸然进行彻底的变革。","部分借鉴，循序渐进","act-10"),
D("d4","欧文能做到，我也能做到！我也要搞改革！",88,"你被欧文的实验深深打动了，决定对自己的工厂进行彻底的改革——缩短工时，提高工资，改善条件，创办学校。虽然阻力很大，但你坚持了下来。","欧文的实验影响了整整一代人。很多有良知的企业家受到欧文的启发，走上了改良的道路。虽然他们没有走社会主义道路，但也推动了社会进步。","深受启发，彻底改革","act-10"),
D("d5","我要和欧文合作，把他的方法推广开来。",85,"你主动联系欧文，表示愿意与他合作，共同推广工厂改革。你还捐款支持他的社会改革实验。","欧文的社会改革实验得到了不少有识之士的支持。虽然他的共产主义公社实验最终失败了，但他的思想影响深远。","携手合作，推广改革","act-10"),
D("d6","他的工厂赚钱是因为位置好资源多，不是因为善待工人。",70,"你认为欧文的工厂盈利是因为其他原因，和善待工人没关系。你觉得如果换个人经营，照样能赚钱。","对于成功，人们总是有不同的解读。有些人愿意学习成功的经验，有些人则总是找理由否定。不同的态度，决定了不同的人生。","不以为然，找借口","act-10"),
D("d7","我要写文章介绍欧文的实验，让更多人知道。",82,"你写了一系列文章，向英国的工厂主们介绍欧文在新拉纳克的实验。虽然很多人不相信，但也有一些人开始反思。","思想的传播需要载体。通过著书立说、写文章介绍，进步的思想才能被更多人了解，才能推动社会的变革。","撰文介绍，传播理念","act-10"),
D("d8","好是好，但成本太高了，我可做不起。",72,"你觉得欧文那套虽然很好，但成本太高，一般工厂主做不起。你还是算了，继续按老办法经营。","企业改革确实需要成本。短期来看，改善工人待遇会增加支出。但从长远来看，这能提高效率，带来更大的收益。问题是，很多人只看眼前。","成本太高，难以承受","act-10"),
D("d9","我要深入研究欧文的思想，形成我自己的管理哲学。",86,"你不仅学习欧文的具体做法，还深入研究他的思想，结合自己的实际情况，形成了一套独特的管理哲学。你的工厂成了远近闻名的模范工厂。","学习不是照搬。真正的学习是吸收精髓，结合实际，形成自己的东西。这样才能超越前人，走出自己的路。","深入研究，自成体系","act-10")]))

# 12c
acts.append(A("act-12c","自由贸易",False,"1840年",
"关于自由贸易的争论越来越激烈了。工业资产阶级要求废除谷物法，实行自由贸易；而土地贵族则坚决反对。你站在哪一边？这不仅关乎国家政策，也直接影响你的生意。",
[N("工厂主同行科布登","兄弟，加入反谷物法同盟吧！废除谷物法，降低粮价，我们才能降低工资成本，工业品才能卖得更便宜！","科"),N("地主出身的议员皮尔","废除谷物法？那我们的农业怎么办？英国的粮食安全谁来保障？你们这些工厂主只想着自己赚钱！","皮")],
[D("d1","我坚决支持自由贸易！加入反谷物法同盟！",88,"你坚决站在自由贸易一边，积极参加反谷物法同盟，又出钱又出力。经过多年斗争，谷物法终于废除了，英国进入了自由贸易的黄金时代。","反谷物法运动是19世纪中期英国工业资产阶级争取自由贸易的重要斗争。1846年谷物法的废除，标志着自由贸易政策在英国的最终确立。","支持自由，参与斗争","act-13"),
D("d2","我支持保护主义，保护我们的民族工业。",65,"你觉得保护主义也有道理——如果外国商品大量涌入，我们的工业也会受冲击。你对自由贸易持怀疑态度。","自由贸易和保护主义是经济政策中永恒的争论。不同的历史时期、不同的利益群体，会有不同的主张。没有绝对的对错，只有是否适合。","怀疑自由，倾向保护","act-13"),
D("d3","我要亲自去欧洲大陆考察，看看那边的情况。",80,"你决定亲自去欧洲大陆考察，看看各国的贸易政策和工业发展情况。这次考察让你对自由贸易有了更全面的认识。","纸上得来终觉浅，绝知此事要躬行。亲自考察比道听途说和书本知识要可靠得多。","实地考察，全面认识","act-13"),
D("d4","自由贸易对我们工厂主有好处，但也要考虑工人的利益。",85,"你支持自由贸易，但也担心工人的利益——万一外国商品涌入导致失业怎么办？你主张在推进自由贸易的同时，也要保障工人的权益。","自由贸易是一把双刃剑。它能降低物价、增加财富，但也可能带来失业和产业冲击。如何在效率和公平之间取得平衡，是一个难题。","支持自由，兼顾公平","act-13"),
D("d5","我要做走私生意，关税越高，走私越赚钱。",62,"你看到了高关税带来的商机——走私。你偷偷干起了走私的勾当，赚了不少黑心钱，但整天提心吊胆，生怕被抓住。","高关税往往伴随着走私。在利润的诱惑下，总有人愿意铤而走险。但走私是违法的，一旦被抓，后果严重。","铤而走险，走私牟利","act-13"),
D("d6","我主张逐步降低关税，平稳过渡。",78,"你支持自由贸易，但不赞成像激进派那样一下废除所有关税。你主张逐步降低，给企业和工人一个适应的过程。","激进改革和渐进改革是两条不同的路径。激进派主张一步到位，渐进派主张平稳过渡。两者各有优劣，需要根据具体情况来判断。","渐进改革，平稳过渡","act-13"),
D("d7","我要成立商会，联合大家一起推动政策。",85,"你发起成立了商会，把工业资产阶级的力量组织起来，共同推动自由贸易政策。集体的力量比个人大得多，你们的声音越来越有分量。","组织起来才有力量。资产阶级很早就懂得了这个道理，他们通过商会、行会等组织来维护共同利益，影响国家政策。","组织商会，集体发声","act-13"),
D("d8","什么自由贸易保护主义，我不懂这些，我只管做生意。",70,"你对这些宏大的经济政策不感兴趣，觉得那是政治家的事。你只关心自己的生意，想方设法把它做好。","并不是所有人都关心国家大事和宏观政策。有些人只埋头于自己的小天地，过好自己的日子就行了。","不关心政治，专注生意","act-13"),
D("d9","我要研究经济学，搞清楚这些理论背后的道理。",86,"你开始系统地学习经济学，从亚当·斯密到李嘉图，你都认真研读。搞懂了理论，你对现实政策的认识也更深刻了。","理论是行动的指南。只有搞懂了背后的理论，才能在复杂的现实中看清方向，做出正确的决策。","学习理论，武装头脑","act-13")]))

print(f"第八组生成完成，共 {len(acts)} 幕")

